#include <iostream>
#include <iomanip>
#include <cmath>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    double prod = 1.0;
    for (int i = 1; i <= n; ++i) {
        prod *= 1.0 + 1.0 / (static_cast<double>(i) * i);
    }

    cout << fixed << setprecision(3) << prod << '\n';

    return 0;
}
